import time
import random
import requests


def retry(fn, attempts=3, base=0.5):
    # Note: catches requests.RequestException only (not bare Exception)
    # so KeyboardInterrupt/SystemExit propagate. See docs/ops_notes.md.
    for i in range(attempts):
        try:
            return fn()
        except requests.RequestException:
            if i == attempts - 1:
                raise
            time.sleep(base * (2 ** i) + random.random() * 0.1)


def fetch(url):
    return retry(lambda: requests.get(url).json())
